class Solution:
    def countGoodNumbers(self, n):
        MOD = 10**9 + 7
        def power(b, e):
            r = 1
            b %= MOD
            while e > 0:
                if e & 1:
                    r = r * b % MOD
                b = b * b % MOD
                e >>= 1
            return r
        even = (n + 1) // 2
        odd = n // 2
        return power(5, even) * power(4, odd) % MOD

