var countGoodNumbers = function(n) {
    const MOD = 1000000007n;
    function power(b, e) {
        let r = 1n;
        b %= MOD;
        while (e > 0n) {
            if (e & 1n) r = r * b % MOD;
            b = b * b % MOD;
            e >>= 1n;
        }
        return r;
    }
    const bn = BigInt(n);
    const even = (bn + 1n) / 2n;
    const odd = bn / 2n;
    return Number(power(5n, even) * power(4n, odd) % MOD);
};
